import { describe, expect, it } from 'bun:test';
import { AccessTrace, makeChameleon, runWithChameleon } from './index';

/** Opaque infinite-depth Chameleon proxy (recursive structural type). */
type ChameleonProxy = Record<string, unknown> & { [k: string]: ChameleonProxy } & ((...args: unknown[]) => ChameleonProxy);

describe('AccessTrace', () => {
  it('records gets with sequence', () => {
    const t = new AccessTrace();
    t.record('.a', 'get', 'a');
    t.record('.a.b', 'get', 'b');
    expect(t.all()).toHaveLength(2);
    expect(t.all()[0].sequence).toBe(0);
    expect(t.all()[1].sequence).toBe(1);
  });

  it('reports unique paths', () => {
    const t = new AccessTrace();
    t.record('.a', 'get', 'a');
    t.record('.a', 'get', 'a');
    t.record('.b', 'get', 'b');
    expect(t.paths().sort()).toEqual(['.a', '.b']);
  });

  it('computes max depth', () => {
    const t = new AccessTrace();
    t.record('.a', 'get', 'a');
    t.record('.a.b.c', 'get', 'c');
    t.record('.d', 'get', 'd');
    expect(t.maxDepth()).toBe(3);
  });
});

describe('makeChameleon', () => {
  it('returns a proxy that survives any property access', () => {
    const { proxy } = makeChameleon();
    const p = proxy as unknown as ChameleonProxy;
    expect(() => p.foo.bar.baz.qux).not.toThrow();
  });

  it('records the access path', () => {
    const { proxy, trace } = makeChameleon();
    const p = proxy as unknown as ChameleonProxy;
    void p.a.b.c;
    expect(trace.paths()).toContain('.a');
    expect(trace.paths()).toContain('.a.b');
    expect(trace.paths()).toContain('.a.b.c');
  });

  it('returns pinned values when path matches', () => {
    const { proxy } = makeChameleon({
      paths: { '.symbol': 'BTC/USD', '.qty': 10 },
    });
    const p = proxy as unknown as ChameleonProxy;
    expect(p.symbol).toBe('BTC/USD');
    expect(p.qty).toBe(10);
  });

  it('returns number default on valueOf (arithmetic coercion)', () => {
    const { proxy } = makeChameleon({ defaults: { number: 42 } });
    const p = proxy as unknown as ChameleonProxy;
    expect((p as unknown as number) + 1).toBe(43);
  });

  it('returns string default on toString', () => {
    const { proxy } = makeChameleon({ defaults: { string: 'hi' } });
    const p = proxy as unknown as ChameleonProxy;
    expect(String(p)).toBe('hi');
  });

  it('returns configurable length on .length', () => {
    const { proxy } = makeChameleon({ defaults: { iterableLength: 5 } });
    const p = proxy as unknown as ChameleonProxy;
    expect(p.length).toBe(5);
    expect(p.data.length).toBe(5);
  });

  it('is iterable with configurable count', () => {
    const { proxy } = makeChameleon({ defaults: { iterableLength: 3 } });
    const arr = [...(proxy as unknown as Iterable<unknown>)];
    expect(arr).toHaveLength(3);
  });

  it('is callable', () => {
    const { proxy, trace } = makeChameleon();
    const p = proxy as unknown as ChameleonProxy;
    const result = p.handler();
    expect(result).toBeDefined();
    expect(trace.all().some((e) => e.kind === 'call')).toBe(true);
  });

  it('pinned paths work after chained access', () => {
    const { proxy } = makeChameleon({
      paths: { '.state.godVM.c1': 42 },
    });
    const p = proxy as unknown as ChameleonProxy;
    expect(p.state.godVM.c1).toBe(42);
  });

  it('ignores then to avoid thenable traps', () => {
    const { proxy } = makeChameleon();
    const p = proxy as unknown as ChameleonProxy;
    expect(p.then).toBeUndefined();
  });
});

describe('runWithChameleon', () => {
  it('captures trace from executed function', () => {
    const fn = (x: Record<string, unknown>) => (x.user as Record<string, unknown>).name;
    const { trace, result } = runWithChameleon(fn);
    expect(result).toBeDefined();
    expect(trace.paths()).toContain('.user');
    expect(trace.paths()).toContain('.user.name');
  });

  it('captures errors without re-throwing', () => {
    const fn = (x: Record<string, unknown>) => {
      if (x.shouldThrow) throw new Error('boom');
      return x.value;
    };
    // shouldThrow is chameleon → truthy (object). So it throws.
    const { error, trace } = runWithChameleon(fn);
    expect(error).toBeInstanceOf(Error);
    expect(trace.paths()).toContain('.shouldThrow');
  });

  it('steers a branch using a pinned path', () => {
    const fn = (x: Record<string, unknown>) => {
      if ((x.count as number) > 5) return 'high';
      return 'low';
    };
    // Chameleon default for number is 0 -> count > 5 is false -> 'low'
    const low = runWithChameleon(fn);
    expect(low.result).toBe('low');

    // Pin count to 10 -> count > 5 is true -> 'high'
    const high = runWithChameleon(fn, { paths: { '.count': 10 } });
    expect(high.result).toBe('high');
  });

  it('handles nested object access on heavy state (regression for tickV31)', () => {
    const tickV31Like = (state: Record<string, unknown>, btcBuffer: number[]) => {
      if (btcBuffer.length >= 2) {
        const m0c = btcBuffer[btcBuffer.length - 1]! - btcBuffer[btcBuffer.length - 2]!;
        if (m0c > 0) ((state.godVM as Record<string, unknown>).state as Record<string, number>).c1 += 1;
      }
      return ((state.godVM as Record<string, unknown>).state as Record<string, unknown>).c1;
    };
    const { result, error, trace } = runWithChameleon(
      (x) => tickV31Like(x as Record<string, unknown>, [1, 2]),
      { paths: { '.godVM.state.c1': 0 } }
    );
    // The assignment `state.godVM.state.c1 += 1` will fail on a chameleon
    // because writing to a pinned primitive isn't supported. That's fine --
    // we care about the access trace.
    expect(trace.paths()).toContain('.godVM');
    // Either it threw (expected for now) or it returned. Trace should have data.
    expect(trace.all().length).toBeGreaterThan(0);
  });
});
